import{SimpleDataAdapter}from"./simple-data-adapter.js";class MultiDataAdapter extends SimpleDataAdapter{constructor(r={}){super(Object.assign({layers:[],valueAccessor:r=>r.value},r))}configure(r){return super.configure(r)}conf(){return super.conf()}data(){return this.layers().map(r=>{var{chartId:e,valueAccessor:a,dimension:t}=this._conf,a=r.valueAccessor||a,t=this._getData({dimension:t,group:r.group,chartId:e,valueAccessor:a});return{name:r.name,rawData:t}})}layers(){if(this._conf.group){const r={name:this._conf.groupName,group:this._conf.group};return[r].concat(this._conf.layers)}return this._conf.layers}layerByName(e){return this._conf.layers.find(r=>r.name===e)}}export{MultiDataAdapter};